// Collect and merge feedback from all available sources
// In a scheduled run, this collects from configured sources.
// In a webhook run, the incoming data is the source.

const triggerNode = $input.first();
const isWebhook = triggerNode.json?.body !== undefined || triggerNode.json?.headers !== undefined;

let rawItems = [];

if (isWebhook) {
  // Single item from webhook
  const body = triggerNode.json.body || triggerNode.json;
  rawItems = Array.isArray(body) ? body : [body];
} else {
  // Scheduled run: use embedded sample data for demo
  // In production: replace this with calls to your actual sources
  // (Google Sheets, database queries, etc.)
  rawItems = [
    {
      id: `demo_${Date.now()}_1`,
      text: "The onboarding flow is confusing — I spent 30 minutes trying to connect my first integration.",
      source: "typeform",
      customer_segment: "startup",
      rating: 2,
      created_at: new Date(Date.now() - 2 * 24 * 60 * 60 * 1000).toISOString()
    },
    {
      id: `demo_${Date.now()}_2`,
      text: "Billing page doesn't show invoice history for the last 3 months. This is a blocker for our finance team.",
      source: "support_email",
      customer_segment: "enterprise",
      rating: null,
      created_at: new Date(Date.now() - 1 * 24 * 60 * 60 * 1000).toISOString()
    },
    {
      id: `demo_${Date.now()}_3`,
      text: "Would love a bulk import feature for contacts. We have 5000 records to migrate.",
      source: "in_app_survey",
      customer_segment: "growth",
      rating: 4,
      created_at: new Date().toISOString()
    },
    {
      id: `demo_${Date.now()}_4`,
      text: "The API rate limit documentation is outdated — it still says 100 req/min but the actual limit is 50.",
      source: "github_issue",
      customer_segment: "enterprise",
      rating: null,
      created_at: new Date(Date.now() - 3 * 24 * 60 * 60 * 1000).toISOString()
    },
    {
      id: `demo_${Date.now()}_5`,
      text: "Performance is great after the last update. Pages load noticeably faster!",
      source: "app_store_review",
      customer_segment: "consumer",
      rating: 5,
      created_at: new Date(Date.now() - 4 * 24 * 60 * 60 * 1000).toISOString()
    }
  ];
}

console.log(`Collected ${rawItems.length} raw feedback items`);

return rawItems.map(item => ({ json: item }));

// Normalise feedback to a consistent schema
// Handles different source formats

const item = $input.first().json;

// Generate a stable ID if missing
const id = item.id || item.uid || item.feedback_id || item.response_id ||
  `fb_${Date.now()}_${Math.random().toString(36).substring(2, 8)}`;

// Normalise text — combine text fields from various sources
const text = (
  item.text ||
  item.message ||
  item.body ||
  item.comment ||
  item.review ||
  item.content ||
  item.feedback ||
  [item.question_1, item.question_2, item.question_3].filter(Boolean).join(' ')
).trim();

if (!text || text.length < 5) {
  // Skip items with no meaningful content
  return [];
}

// Normalise source
const sourceRaw = (item.source || item.channel || item.form_name || 'unknown').toLowerCase();
const sourceMap = {
  typeform: 'typeform', surveymonkey: 'survey', google_forms: 'survey',
  intercom: 'support', zendesk: 'support', freshdesk: 'support', support_email: 'support',
  app_store_review: 'app_review', play_store_review: 'app_review',
  github_issue: 'github', github_discussion: 'github',
  in_app_survey: 'in_app', in_app_feedback: 'in_app',
  csv: 'csv', webhook: 'webhook',
};
const source = sourceMap[sourceRaw] || sourceRaw;

// Normalise rating (0–10 scale)
let rating = null;
if (item.rating !== null && item.rating !== undefined) {
  const raw = parseFloat(item.rating);
  if (!isNaN(raw)) {
    // Detect scale and normalise to 0–10
    if (raw <= 1) rating = Math.round(raw * 10);
    else if (raw <= 5) rating = Math.round(raw * 2);
    else if (raw <= 10) rating = Math.round(raw);
  }
}

// Normalise segment
const segmentRaw = (item.customer_segment || item.plan || item.tier || 'unknown').toLowerCase();
const segments = ['enterprise', 'growth', 'startup', 'consumer', 'free', 'trial'];
const segment = segments.find(s => segmentRaw.includes(s)) || 'unknown';

// Create deduplication hash
const normalizedText = text.toLowerCase().replace(/\s+/g, ' ').trim();
const hashInput = `${source}:${normalizedText.substring(0, 200)}`;
// Simple hash (SHA-256 would require crypto — using a fast polynomial hash)
let dedupHash = 0;
for (let i = 0; i < hashInput.length; i++) {
  dedupHash = ((dedupHash << 5) - dedupHash) + hashInput.charCodeAt(i);
  dedupHash |= 0;
}
dedupHash = Math.abs(dedupHash).toString(36);

return [{
  json: {
    id,
    text,
    source,
    source_raw: sourceRaw,
    customer_segment: segment,
    rating,
    created_at: item.created_at || item.timestamp || item.submitted_at || new Date().toISOString(),
    received_at: new Date().toISOString(),
    dedup_hash: dedupHash,
    char_count: text.length,
  }
}];

// Deduplicate feedback items within the configured time window
// In the basic stack, we use an in-memory check for this run.
// In the advanced stack, query PostgreSQL for existing hashes.

// Collect all items from this run
const items = $input.all().map(i => i.json);

// In-memory dedup for this run
const seenHashes = new Set();
const unique = [];
const duplicates = [];

for (const item of items) {
  if (seenHashes.has(item.dedup_hash)) {
    duplicates.push(item.id);
  } else {
    seenHashes.add(item.dedup_hash);
    unique.push(item);
  }
}

console.log(`Dedup: ${unique.length} unique, ${duplicates.length} duplicates from ${items.length} total`);

// Return unique items for classification
return unique.map(item => ({ json: item }));

// Prepare batch for the LLM Classifier subworkflow
const batchItems = $input.all().map(i => i.json);

return [{
  json: {
    mode: 'feedback',
    items: batchItems.map(item => ({
      id: item.id,
      text: item.text,
      metadata: {
        source: item.source,
        customer_segment: item.customer_segment,
        rating: item.rating,
        created_at: item.created_at,
      }
    }))
  }
}];

// Merge classification results with original feedback items
// The classifier returns { results: [{id, classification, confidence, reasoning}] }

const classifierOutput = $input.first().json;
const results = classifierOutput.results || [];

// Build a map for fast lookup
const classMap = new Map(results.map(r => [r.id, r]));

// We need to join with the original normalised items
// They're available in the batch node's input
const originalItems = $('Batch: 10 Items for AI').all().map(i => i.json);

const classified = originalItems.map(item => {
  const classResult = classMap.get(item.id);
  return {
    ...item,
    classification: classResult?.classification || null,
    confidence: classResult?.confidence || 0,
    reasoning: classResult?.reasoning || '',
    classified_at: new Date().toISOString(),
  };
});

return classified.map(item => ({ json: item }));

// Aggregate all classified items and generate a product insights report

const allItems = $input.all().map(i => i.json);

const periodStart = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString();
const periodEnd = new Date().toISOString();

// Group by problem category
const byCategory = {};
const bySegment = {};
const featureRequests = [];
const bugReports = [];
const criticalItems = [];
const quotes = [];

for (const item of allItems) {
  const cls = item.classification || {};
  const cat = cls.problem_category || 'other';
  const seg = item.customer_segment || 'unknown';

  // Category grouping
  if (!byCategory[cat]) byCategory[cat] = [];
  byCategory[cat].push(item);

  // Segment grouping
  if (!bySegment[seg]) bySegment[seg] = [];
  bySegment[seg].push(item);

  // Feature requests
  if (cls.is_feature_request) featureRequests.push(item);

  // Bug reports
  if (cls.is_bug_report) bugReports.push(item);

  // Critical/urgent
  if (cls.urgency === 'critical' || cls.urgency === 'high') criticalItems.push(item);

  // Key quotes
  if (cls.key_quote && item.confidence > 0.7) {
    quotes.push({
      quote: cls.key_quote,
      source: item.source,
      segment: item.customer_segment,
      category: cat,
    });
  }
}

// Top problems by frequency
const topProblems = Object.entries(byCategory)
  .sort((a, b) => b[1].length - a[1].length)
  .slice(0, 5)
  .map(([category, items]) => ({
    category,
    count: items.length,
    affected_segments: [...new Set(items.map(i => i.customer_segment))],
    avg_confidence: (items.reduce((s, i) => s + i.confidence, 0) / items.length).toFixed(2),
    urgency_breakdown: items.reduce((acc, i) => {
      const u = i.classification?.urgency || 'unknown';
      acc[u] = (acc[u] || 0) + 1;
      return acc;
    }, {}),
  }));

// Affected segments summary
const segmentSummary = Object.entries(bySegment).map(([seg, items]) => ({
  segment: seg,
  total_feedback: items.length,
  top_issues: Object.entries(
    items.reduce((acc, i) => {
      const cat = i.classification?.problem_category || 'other';
      acc[cat] = (acc[cat] || 0) + 1;
      return acc;
    }, {})
  ).sort((a, b) => b[1] - a[1]).slice(0, 3).map(([k, v]) => `${k} (${v})`),
}));

const report = {
  meta: {
    generated_at: new Date().toISOString(),
    period_start: periodStart,
    period_end: periodEnd,
    total_feedback_items: allItems.length,
    items_classified: allItems.filter(i => i.classification).length,
    company: process.env.COMPANY_NAME || 'Your Company',
  },
  top_repeated_problems: topProblems,
  emerging_problems: topProblems.filter(p => p.count === 1).slice(0, 3),
  important_quotes: quotes.slice(0, 5),
  feature_requests: featureRequests.slice(0, 10).map(i => ({
    text: i.text.substring(0, 200),
    segment: i.customer_segment,
    source: i.source,
    confidence: i.confidence,
  })),
  possible_bugs: bugReports.slice(0, 5).map(i => ({
    text: i.text.substring(0, 200),
    segment: i.customer_segment,
    urgency: i.classification?.urgency || 'unknown',
    confidence: i.confidence,
  })),
  affected_segments: segmentSummary,
  critical_and_urgent: criticalItems.length,
  recommendations: [
    topProblems[0] ? `Prioritise fixing ${topProblems[0].category} — ${topProblems[0].count} reports, affecting ${topProblems[0].affected_segments.join(', ')}` : null,
    bugReports.length > 0 ? `Investigate ${bugReports.length} potential bug report(s) before next release` : null,
    featureRequests.length > 0 ? `Add ${featureRequests.length} feature request(s) to the backlog for review` : null,
  ].filter(Boolean),
};

console.log(`Report generated: ${allItems.length} items, ${topProblems.length} top problems, ${featureRequests.length} feature requests`);

return [{ json: report }];

// Format the approved report as a notification message
const approval = $input.first().json;
const report = $('Generate Product Insights Report').first().json;

const topProbs = report.top_repeated_problems.slice(0, 3)
  .map((p, i) => `${i + 1}. **${p.category}** — ${p.count} reports (${p.affected_segments.join(', ')})`)
  .join('\n');

const featReqs = report.feature_requests.slice(0, 3)
  .map((r, i) => `${i + 1}. "${r.text.substring(0, 100)}..." — ${r.segment}`)
  .join('\n');

const bugs = report.possible_bugs.slice(0, 2)
  .map((b, i) => `${i + 1}. "${b.text.substring(0, 100)}..." (${b.urgency})`)
  .join('\n');

const body = `
📊 **Weekly Product Insights — ${report.meta.company}**
📅 Period: ${report.meta.period_start.substring(0, 10)} → ${report.meta.period_end.substring(0, 10)}
📝 Items analysed: ${report.meta.total_feedback_items}

**🔴 Top Problems:**
${topProbs || 'None identified'}

**💡 Feature Requests (${report.feature_requests.length} total):**
${featReqs || 'None this week'}

**🐛 Possible Bugs (${report.possible_bugs.length} total):**
${bugs || 'None this week'}

**✅ Recommendations:**
${report.recommendations.map((r, i) => `${i + 1}. ${r}`).join('\n')}
`.trim();

return [{
  json: {
    channel: process.env.NOTIFICATION_CHANNEL || 'email',
    title: `Weekly Product Insights — ${report.meta.company}`,
    body,
    urgency: report.critical_and_urgent > 0 ? 'high' : 'medium',
    metadata: { report_period: report.meta.period_start }
  }
}];

// Log rejection or timeout
const approval = $input.first().json;
console.log(`Report ${approval.decision}: ${approval.comment || 'no comment'}`);
return [{ json: { logged: true, decision: approval.decision, at: new Date().toISOString() } }];
